int LevenshteinDistance(char *s1, char *s2) {
    int s1len, s2len, x, y, lastdiag, olddiag;
    s1len = strlen(s1);
    s2len = strlen(s2);
    unsigned int column[s1len+1];
    for (y = 1; y <= s1len; y++)
        column[y] = y;
    for (x = 1; x <= s2len; x++) {
        column[0] = x;
        for (y = 1, lastdiag = x-1; y <= s1len; y++) {
            olddiag = column[y];
            if (s1[y-1] == s2[x-1])
                column[y] = lastdiag;
            else 
                column[y] = min( column[y] + 1, min(column[y-1] + 1, lastdiag + 2));
            lastdiag = olddiag;
        }
    }
    return(column[s1len]);
}

