class Vector2D:
    """Represents a 2D vector with the basic vector operations- addition, subtraction, dot product, and cross product."""

    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __add__(self, other):
        """Adds two vectors."""
        x = self.x + other.x
        y = self.y + other.y
        return Vector2D(x, y)

    def __sub__(self, other):
        """Subtracts two vectors."""
        x = self.x - other.x
        y = self.y - other.y
        return Vector2D(x, y)

    def dot(self, other):
        """Returns the dot product of two vectors."""
        return self.x * other.x + self.y * other.y

    def cross(self, other):
        """Returns the cross product of two vectors."""
        return self.x * other.y - self.y * other.x

